// Learn: Use an index when position matters.
int[] scores = { 8, -1, 10, 0 };
int total = 0;
for (int i = 0; i < scores.length; i++) {
  // continue skips this negative score.
  if (scores[i] < 0) continue;
  if (scores[i] == 0) break;
  total += scores[i];
}
System.out.println(total);
